mapper.select:
SELECT COUNT(*)
FROM dc3_entity_alarm
WHERE deleted = 0
AND tenant_id = #{tenantId}
AND alarm_target_type_flag = 1
AND alarm_target_type_flag = 0
AND alarm_target_type_flag = 2
AND alarm_type_flag = #{alarmTypeFlag}
AND confirm_flag = #{confirmFlag}
AND create_time >= #{from}

SELECT EXTRACT(DOW FROM create_time)::int  AS dow, EXTRACT(HOUR FROM create_time)::int AS hour, COUNT(*) AS count
FROM dc3_entity_alarm
WHERE deleted = 0
  AND tenant_id = #{tenantId}
  AND create_time >= #{from}
GROUP BY dow, hour
